import{_ as i,o as a,c as t,ae as o}from"./chunks/framework.BD9pLfSD.js";const _=JSON.parse('{"title":"Helius RPC Setup (Infra)","description":"","frontmatter":{},"headers":[],"relativePath":"docs/infra/helius_rpc.md","filePath":"docs/infra/helius_rpc.md"}'),s={name:"docs/infra/helius_rpc.md"};function r(l,e,n,c,p,d){return a(),t("div",null,[...e[0]||(e[0]=[o(`<h1 id="helius-rpc-setup-infra" tabindex="-1">Helius RPC Setup (Infra) <a class="header-anchor" href="#helius-rpc-setup-infra" aria-label="Permalink to &quot;Helius RPC Setup (Infra)&quot;">​</a></h1><p>This repo expects a reliable RPC endpoint for devnet demos. Use Helius if available.</p><h2 id="environment-variables" tabindex="-1">Environment Variables <a class="header-anchor" href="#environment-variables" aria-label="Permalink to &quot;Environment Variables&quot;">​</a></h2><ul><li><code>XB77_RPC_URL</code>: Full RPC URL to use (overrides everything).</li><li><code>XB77_HELIUS_API_KEY</code>: Helius API key for devnet/mainnet RPC.</li><li><code>XB77_HELIUS_NETWORK</code>: <code>devnet</code> (default) or <code>mainnet</code>.</li><li><code>XB77_CU_LIMIT</code>: Optional compute unit limit for smoke tests.</li><li><code>XB77_CU_PRICE</code>: Optional compute unit price (micro-lamports) for priority fees.</li></ul><p>Example (devnet):</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>export XB77_HELIUS_API_KEY=&quot;YOUR_KEY&quot;</span></span>
<span class="line"><span>export XB77_HELIUS_NETWORK=&quot;devnet&quot;</span></span></code></pre></div><h2 id="smoke-test-script" tabindex="-1">Smoke Test Script <a class="header-anchor" href="#smoke-test-script" aria-label="Permalink to &quot;Smoke Test Script&quot;">​</a></h2><p>Use the SDK script to send a minimal transfer through Helius:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>bun run sdk/scripts/helius_rpc_smoke.ts --airdrop-sol 1 --lamports 1</span></span></code></pre></div><p>Options:</p><ul><li><code>--rpc</code>: Explicit RPC URL.</li><li><code>--keypair</code>: Path to a Solana keypair JSON file.</li><li><code>--keypair-json</code>: Inline JSON array for the keypair.</li><li><code>--to</code>: Recipient address (defaults to self).</li><li><code>--lamports</code>: Transfer amount.</li><li><code>--cu-limit</code>: Compute unit limit.</li><li><code>--cu-price</code>: Compute unit price (micro-lamports).</li><li><code>--airdrop-sol</code>: Request a devnet airdrop first.</li></ul><p>If you use the MCP server, keep <code>XB77_KEYPAIR_PATH</code> or <code>XB77_KEYPAIR_JSON</code> set so the same keypair works across flows.</p>`,12)])])}const h=i(s,[["render",r]]);export{_ as __pageData,h as default};
